<template>
  <div>
    a标签测试
    <a
      class="link external"
      href="http://www.kaiyuancn.com/Cn/Index/listView/catid/20.html"
      style="width: 500px; height: 50px; background: red; display: blck"
      >cccc</a
    ><br /><br />
    <a
      class="link external"
      href="http://www.kaiyuancn.com/Public/Uploads/uploadfile/files/20180928/20180928170508_5badeec455d4d.xls"
      download="客户联系单.xls"
      style="width: 50px; height: 50px; background: red"
      >a标签 H5 文件下载</a
    ><br /><br />

    选相册和相机照片：<br />
    <input type="file" accept="image/*" id="input" /><br />
    选相机照片：<br />
    <input type="file" accept="image/*" capture="camera" id="input" /><br />
    录像：<br />
    <input type="file" accept="video/*" capture="camcorder" id="input" /><br />
    录音：<br />
    <input type="file" accept="audio/*" capture="microphone" id="input" /><br />

    参考：https://blog.csdn.net/rui_code/article/details/84584521

    <div>
      <img id="show-img" src="" />
      <input
        type="file"
        accept="image/*"
        capture="camera"
        id="input"
        value="点击打开相机"
      />
    </div>
  </div>
</template>

<script>
export default {
  name: "h5camera", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {
    var img = document.getElementById("show-img");
    var input = document.getElementById("input");
    input.addEventListener("change", function (e) {
      alert("触发change事件");
      console.log("change", e);
      var file = e.target.files[0];
      e.target.value = "";
      var uri = URL.createObjectURL(file);
      img.src = uri;
    });
    input.addEventListener("input", function (e) {
      alert("触发input事件");
      console.log("input", e);
    });
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    publicbFunction() {},
    _privateFunction() {},
  },
};
</script>
